    echo "HIT $i"; echo "$body" | sed -n '1,80p'; break; 
  fi;
  # Also search explicit word FLAG
  if echo "$body" | grep -q -i "FLAG"; then 
    echo "MAYBE $i"; echo "$body" | sed -n '1,80p'; break; 
  fi;
  # Progress
  if [ $((i % 50)) -eq 0 ]; then echo "Checked up to $i" 1>&2; fi
 done'
